solutions.javascript:
// Define the function to fix MongoDB pipeline
function fixPipeline(pipeline, fields) {
    // Use the $type operator to check the type of each field in the projection stage
    pipeline.push({ $project: { _id: 1, name: 1, age: 1 } });
    // Use the $ifNull operator to check if a field is null
    pipeline.push({ $project: { address: { $ifNull: { $type: '$address', 'object' } } } });
    // Use the $ne operator to check if a field is not equal to an empty string
    pipeline.push({ $project: { address: { street: { $ne: '$address.street', '' } } } });
    return pipeline;
}
